/**
 * I18nContext.jsx — App-wide internationalisation.
 *
 * Supported languages:
 *   en  English (default)
 *   fr  French
 *   es  Spanish
 *   zh  Chinese (Simplified)
 *   ar  Arabic
 *   it  Italian
 *   de  German
 *
 * Usage:
 *   const { t, lang, setLang } = useI18n();
 *   t('search.title')   →  "Search Questions"  (or translated)
 *
 * Only high-visibility UI strings are translated here — titles, tab labels,
 * buttons, section headers, and key messages. Body prose is generated by AI
 * and already respects the user's topic language.
 */
